"""
This module contains the logic for managing the Checkers game.
"""

import numpy as np

class Piece:
    def __init__(self, color):
        self.color = color
        self.is_king = False

    def promote(self):
        self.is_king = True

class Board:
    def __init__(self):
        self.board = self.create_board()

    def create_board(self):
        board = np.zeros((8, 8), dtype=object)
        for i in range(3):
            for j in range(i % 2, 8, 2):
                board[i, j] = Piece('black')
        for i in range(5, 8):
            for j in range(i % 2, 8, 2):
                board[i, j] = Piece('white')
        return board

    def move_piece(self, from_pos, to_pos):
        if self.board[from_pos[0], from_pos[1]]:
            piece = self.board[from_pos[0], from_pos[1]]
            self.board[from_pos[0], from_pos[1]] = None
            self.board[to_pos[0], to_pos[1]] = piece

class GameLogic:
    def __init__(self):
        self.board = Board()

    def is_valid_move(self, from_pos, to_pos):
        # Simplified validation for demonstration purposes
        return np.allclose(from_pos, to_pos)

    def make_move(self, from_pos, to_pos):
        if self.is_valid_move(from_pos, to_pos):
            self.board.move_piece(from_pos, to_pos)
            return True
        return False

class Player:
    def __init__(self, color):
        self.color = color

    def get_move(self):
        # Simplified input for demonstration purposes
        from_pos = tuple(map(int, input(f"Enter move from (row col): ").split()))
        to_pos = tuple(map(int, input(f"Enter move to (row col): ").split()))
        return from_pos, to_pos

if __name__ == "__main__":
    game = GameLogic()
    player1 = Player('black')
    player2 = Player('white')

    while True:
        game.make_move(*player1.get_move())
        game.make_move(*player2.get_move())
```

